/**
 * Email Sending Edge Function
 * 
 * Sends transactional emails via Resend with automatic retry logic.
 * 
 * POST /functions/v1/send-email
 * {
 *   "to": "user@example.com" | ["user1@example.com", "user2@example.com"],
 *   "subject": "Email Subject",
 *   "html": "<p>HTML content</p>",
 *   "template": "welcome" (optional),
 *   "templateData": {...} (optional),
 *   "replyTo": "support@example.com" (optional)
 * }
 */

import { serve } from "https://deno.land/std@0.208.0/http/server.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization",
};

interface EmailPayload {
  to: string | string[];
  subject: string;
  html?: string;
  text?: string;
  template?: string;
  templateData?: Record<string, unknown>;
  from?: string;
  replyTo?: string;
  tags?: string[];
}

async function sendViaResend(
  to: string[],
  subject: string,
  html: string,
  from: string,
  replyTo: string,
  tags?: string[]
) {
  const apiKey = Deno.env.get("RESEND_API_KEY");
  if (!apiKey) {
    throw new Error("RESEND_API_KEY not configured");
  }

  const response = await fetch("https://api.resend.com/emails", {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      from,
      to,
      subject,
      html,
      reply_to: replyTo,
      tags: tags?.map((tag) => ({ name: tag, value: "true" })),
    }),
  });

  const data = await response.json();

  if (!response.ok) {
    throw new Error(`Resend API error: ${data.message}`);
  }

  return data;
}

async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  maxRetries = 3,
  baseDelayMs = 1000
): Promise<T> {
  let lastError: unknown;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      if (i < maxRetries - 1) {
        const delayMs = baseDelayMs * Math.pow(2, i);
        await new Promise((resolve) => setTimeout(resolve, delayMs));
      }
    }
  }

  throw lastError;
}

serve(async (req) => {
  // Handle CORS preflight
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  if (req.method !== "POST") {
    return new Response(
      JSON.stringify({ error: "Method not allowed" }),
      { status: 405, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }

  try {
    const payload = (await req.json()) as EmailPayload;

    // Validate required fields
    if (!payload.to || !payload.subject) {
      return new Response(
        JSON.stringify({ error: "Missing required fields: to, subject" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    if (!payload.html && !payload.text && !payload.template) {
      return new Response(
        JSON.stringify({ error: "Missing content: provide html, text, or template" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const to = Array.isArray(payload.to) ? payload.to : [payload.to];
    const from = payload.from || "Restaurant Hub <orders@restaurant-hub.com>";
    const replyTo = payload.replyTo || "support@restaurant-hub.com";
    let html = payload.html || "";

    // If template is specified, use it (simplified - can be extended)
    if (payload.template && payload.templateData) {
      // In production, you'd load actual templates from database or file
      // For now, just use the provided HTML
      html = payload.html || `<p>${JSON.stringify(payload.templateData)}</p>`;
    }

    // Send email with automatic retry
    const result = await retryWithBackoff(() =>
      sendViaResend(to, payload.subject, html, from, replyTo, payload.tags)
    );

    console.log(`📧 Email sent successfully: ${result.id}`);

    return new Response(
      JSON.stringify({
        success: true,
        messageId: result.id,
      }),
      { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("Error sending email:", error);
    return new Response(
      JSON.stringify({
        error: error instanceof Error ? error.message : "Failed to send email",
      }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

/**
 * Shared database utilities for Edge Functions
 */

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

export function createSupabaseClient() {
  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

  if (!supabaseUrl || !supabaseServiceKey) {
    throw new Error("Missing Supabase credentials");
  }

  return createClient(supabaseUrl, supabaseServiceKey);
}

export function createSupabaseUserClient(token: string) {
  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY");

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error("Missing Supabase credentials");
  }

  return createClient(supabaseUrl, supabaseAnonKey, {
    global: {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    },
  });
}

/**
 * Shared error handling for Edge Functions
 */

export class EdgeFunctionError extends Error {
  constructor(
    public statusCode: number,
    message: string,
    public details?: Record<string, unknown>
  ) {
    super(message);
    this.name = "EdgeFunctionError";
  }
}

export function handleError(error: unknown) {
  console.error("Error:", error);

  if (error instanceof EdgeFunctionError) {
    return new Response(
      JSON.stringify({
        error: error.message,
        details: error.details,
      }),
      {
        status: error.statusCode,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  if (error instanceof Error) {
    return new Response(
      JSON.stringify({
        error: error.message,
      }),
      {
        status: 500,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  return new Response(
    JSON.stringify({
      error: "Internal server error",
    }),
    {
      status: 500,
      headers: { "Content-Type": "application/json" },
    }
  );
}

export async function withRetry<T>(
  fn: () => Promise<T>,
  maxRetries = 3,
  delayMs = 1000
): Promise<T> {
  let lastError: Error | unknown;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      if (i < maxRetries - 1) {
        await new Promise((resolve) => setTimeout(resolve, delayMs * Math.pow(2, i)));
      }
    }
  }

  throw lastError;
}

/**
 * Shared types for Edge Functions
 */

export interface EdgeFunctionRequest extends Request {
  auth?: {
    user?: {
      id: string;
      email: string;
      [key: string]: unknown;
    };
  };
}

export interface EmailPayload {
  to: string | string[];
  subject: string;
  template?: string;
  templateData?: Record<string, unknown>;
  html?: string;
  text?: string;
  from?: string;
  replyTo?: string;
  tags?: string[];
}

export interface RateLimitPayload {
  identifier: string;
  limitType: "login" | "signup" | "api" | "anon" | "passwordReset";
}

export interface WebhookPayload {
  type: string;
  [key: string]: unknown;
}

export interface ChatPayload {
  messages: Array<{
    role: "user" | "assistant" | "system";
    content: string;
  }>;
  context?: Record<string, unknown>;
  model?: "groq" | "openai";
}

export interface TurnstilePayload {
  token: string;
  remoteIp?: string;
}
